import type { DeviceCategory } from "@/canvas/device"
import netboxData from "./netbox-catalog.json"

export interface CatalogDevice {
  catalogId: string
  name: string
  manufacturer: string
  model: string
  uHeight: number
  isFullDepth: boolean
  powerWatts: number
  weightKg: number
  category: DeviceCategory
  frontImageUrl: string | null
  rearImageUrl: string | null
}

// --- NetBox catalog (generated by scripts/import-netbox-catalog.ts) ---

interface NetBoxEntry {
  manufacturer: string
  model: string
  slug: string
  uHeight: number
  isFullDepth: boolean
  weightKg: number | null
  maxPowerWatts: number | null
  category: string
  frontImageUrl: string | null
  rearImageUrl: string | null
}

const VALID_CATEGORIES = new Set<string>([
  "server", "switch", "patch_panel", "pdu", "storage", "ups", "blank", "other",
])

const _netboxCatalog: CatalogDevice[] = (netboxData.devices as NetBoxEntry[]).map((d) => ({
  catalogId: `nb-${d.slug}`,
  name: d.model,
  manufacturer: d.manufacturer,
  model: d.model,
  uHeight: d.uHeight,
  isFullDepth: d.isFullDepth,
  powerWatts: d.maxPowerWatts ?? 0,
  weightKg: d.weightKg ?? 0,
  category: (VALID_CATEGORIES.has(d.category) ? d.category : "other") as DeviceCategory,
  frontImageUrl: d.frontImageUrl ?? null,
  rearImageUrl: d.rearImageUrl ?? null,
}))

