/** Full device catalog: NetBox community library if available, otherwise built-in fallbacks. */
export function getCatalogDevices(): CatalogDevice[] {
  if (_netboxCatalog.length > 0) return _netboxCatalog
  return BUILTIN_DEVICES
}

// --- Image URL lookup ---

let _imageUrlMap: Map<string, { front: string | null; rear: string | null }> | null = null

export function getDeviceImageUrl(catalogId: string, face: "front" | "rear"): string | null {
  if (!_imageUrlMap) {
    _imageUrlMap = new Map()
    for (const d of _netboxCatalog) {
      _imageUrlMap.set(d.catalogId, { front: d.frontImageUrl, rear: d.rearImageUrl })
    }
  }
  const entry = _imageUrlMap.get(catalogId)
  if (!entry) return null
  return face === "rear" ? entry.rear : entry.front
}

/**
 * @deprecated Use getCatalogDevices() instead. Kept for backward compatibility.
 */
